                    ret_str.Append(f"application-sets {self.term.replacement_application_name}-app;")
                else:
                    ret_str.Append(f"application-sets {self.filter_name[:((MAX_IDENTIFIER_LEN) // 2)]}{self.term.name[-((MAX_IDENTIFIER_LEN) // 2):]}-app;")
            ret_str.Append('}')  # from {...}

        ret_str.Append('then {')
        # ACTION
        for action in self.term.action:
            ret_str.Append(f"{self._ACTIONS.get(str(action))};")
        if self.term.logging and 'disable' not in [x.value for x in self.term.logging]:
            ret_str.Append('syslog;')
        ret_str.Append('}')  # then {...}
        ret_str.Append('}')  # term {...}
    return str(ret_str)

