                album_id, f'Downloading page {api_page}', query=query, headers={
                    'Authorization': f'jwt {authorization}',
                })['data']
        except ExtractorError as e:
            if isinstance(e.cause, compat_HTTPError) and e.cause.code == 400:
                return
        for video in videos:
            link = video.get('link')
            if not link:
                continue
            uri = video.get('uri')
